import 'package:flutter/material.dart'; class AvatarCircle extends StatelessWidget { final String name; final double radius; const AvatarCircle({super.key, required this.name, this.radius=20}); @override Widget build(BuildContext context) => CircleAvatar(radius:radius, backgroundColor:const Color(0xFF6366F1), child:Text(name.isNotEmpty?name[0].toUpperCase():'?', style:TextStyle(fontSize:radius*0.8,fontWeight:FontWeight.w900,color:Colors.white))); }
